// // This module compares the input voltage (Vin) to the reference voltage (Vref). If Vin is less than Vref, the output (Vout) will indicate a high signal (1), otherwise, it will be low (0).
module voltage_sensor (
    input [7:0] Vin,
    input [7:0] Vref,
    output Vout
);
    assign Vout = (Vin > Vref) ? 1'b1 : 1'b0;
endmodule
